mapper.select:
SELECT COUNT(*) FROM PLACE P JOIN REGION R ON P.PLC_RGN_CD = R.RGN_CD WHERE P.PLC_USE_YN = 'Y' AND (P.PLC_NAME LIKE CONCAT('%', #{keyword}, '%') OR P.PLC_OVERVIEW LIKE CONCAT('%', #{keyword}, '%'))
AND P.PLC_CAT_CD = #{category}
AND R.RGN_NAME = #{region}

SELECT P.PLC_NO AS plcNo, P.PLC_ID AS plcId, P.PLC_CAT_CD AS plcCatCd, P.PLC_NAME AS plcName, P.PLC_OVERVIEW AS plcOverview, P.PLC_MAIN_IMG_URL AS plcMainImgUrl, P.PLC_ADDR AS plcAddr, P.PLC_AVG_RATING AS plcAvgRating, P.PLC_REVIEW_CNT AS plcReviewCnt FROM PLACE P JOIN REGION R ON P.PLC_RGN_CD = R.RGN_CD WHERE P.PLC_USE_YN = 'Y' AND (P.PLC_NAME LIKE CONCAT('%', #{keyword}, '%') OR P.PLC_OVERVIEW LIKE CONCAT('%', #{keyword}, '%'))
AND P.PLC_CAT_CD = #{category}
AND R.RGN_NAME = #{region}
ORDER BY P.PLC_REG_DATE DESC LIMIT #{offset}, #{size}
